case class Product(id: Long, name: String, description: String, category: String, brand: String, price: BigDecimal, inStock: Boolean)

@Singleton
class ProductSearchController @Inject()(
    cc: ControllerComponents,
    dbConfigProvider: DatabaseConfigProvider
)(implicit ec: ExecutionContext) extends AbstractController(cc) {

  private val dbConfig = dbConfigProvider.get[JdbcProfile]
  import dbConfig.profile.api._

  implicit val getProduct: GetResult[Product] = GetResult { r =>
    Product(
      id = r.nextLong(),
      name = r.nextString(),
      description = r.nextString(),
      category = r.nextString(),
      brand = r.nextString(),
      price = r.nextBigDecimal(),
      inStock = r.nextBoolean()
    )
  }

  def search: Action[AnyContent] = Action.async { request =>
    val params = request.queryString.view.mapValues(_.headOption.getOrElse("")).toMap

    val conditions = scala.collection.mutable.ArrayBuffer[SQLActionBuilder]()
    val bindValues = scala.collection.mutable.ArrayBuffer[Any]()

    params.get("name").filter(_.nonEmpty).foreach { value =>
      conditions += sql"LOWER(name) LIKE LOWER(${"%" + value + "%"})"
    }

    params.get("category").filter(_.nonEmpty).foreach { value =>
      conditions += sql"category = $value"
    }

    params.get("brand").filter(_.nonEmpty).foreach { value =>
      conditions += sql"brand = $value"
    }

    params.get("minPrice").filter(_.nonEmpty).foreach { value =>
      scala.util.Try(BigDecimal(value)).toOption.foreach { p =>
        conditions += sql"price >= $p"
      }
    }

    params.get("maxPrice").filter(_.nonEmpty).foreach { value =>
      scala.util.Try(BigDecimal(value)).toOption.foreach { p =>
        conditions += sql"price <= $p"
      }
    }

    params.get("inStock").filter(_.nonEmpty).foreach { value =>
      scala.util.Try(value.toBoolean).toOption.foreach { b =>
        conditions += sql"in_stock = $b"
      }
    }

    params.get("q").filter(_.nonEmpty).foreach { value =>
      val like = "%" + value + "%"
      conditions += sql"(LOWER(name) LIKE LOWER($like) OR LOWER(description) LIKE LOWER($like))"
    }

    val whereFragment: SQLActionBuilder =
      if (conditions.isEmpty) sql"1 = 1"
      else conditions.reduceLeft((a, b) => a ++ sql" AND " ++ b)

    val query = sql"SELECT id, name, description, category, brand, price, in_stock FROM products WHERE " ++ whereFragment

    dbConfig.db.run(query.as[Product]).map { products =>
      Ok(play.api.libs.json.Json.toJson(products.map { p =>
        play.api.libs.json.Json.obj(
          "id" -> p.id,
          "name" -> p.name,
          "description" -> p.description,
          "category" -> p.category,
          "brand" -> p.brand,
          "price" -> p.price,
          "inStock" -> p.inStock
        )
      }))
    }.recover {
      case e: Throwable => InternalServerError(e.getMessage)
    }
  }
}